import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiShield, 
  FiArrowLeft, 
  FiUsers, 
  FiCalendar, 
  FiDollarSign,
  FiTrendingUp,
  FiUserPlus,
  FiSettings,
  FiLogOut,
  FiBarChart,
  FiCheckCircle,
  FiClock,
  FiXCircle,
  FiEye,
  FiPackage,
  FiGift
} from 'react-icons/fi';
import { MdVisibility, MdReply, MdViewList, MdViewModule, MdSearch, MdFilterList } from 'react-icons/md';
import { useAuth } from '../context/AuthContext';
import { Booking, Employee, ContactQuery } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';
import axios from 'axios';
import { getApiUrl } from '../config/api';
import Modal from '../components/Modal'; // Added Modal import

const AdminDashboard: React.FC = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'overview' | 'bookings' | 'employees' | 'queries' | 'services' | 'offers'>('overview');
  const [bookingsTab, setBookingsTab] = useState<'all' | 'pending' | 'accepted' | 'completed'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [assignTechId, setAssignTechId] = useState<string>('');
  const [assignLoading, setAssignLoading] = useState(false);
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [queryViewMode, setQueryViewMode] = useState<'table' | 'card'>('table');
  const [showQueryModal, setShowQueryModal] = useState(false);
  const [showRespondModal, setShowRespondModal] = useState(false);
  const [selectedQuery, setSelectedQuery] = useState<any>(null);
  const [respondText, setRespondText] = useState('');
  const [respondLoading, setRespondLoading] = useState(false);
  const [querySearch, setQuerySearch] = useState('');
  const [showFilterDropdown, setShowFilterDropdown] = useState(false);
  const [statusFilter, setStatusFilter] = useState('all');
  const [dateFilter, setDateFilter] = useState('all');

  // No strict user.id or user.name checks here; just rely on ProtectedRoute
  const sessionId = localStorage.getItem('sessionId');
  // Fetch dashboard data
  const { data: bookingsData, isLoading: bookingsLoading } = useQuery(
    'admin-bookings',
    () => apiService.get<{ bookings: Booking[] }>(`${API_ENDPOINTS.ADMIN_ORDERS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load bookings');
      }
    }
  );

  const { data: employeesData, isLoading: employeesLoading } = useQuery(
    'employees',
    () => apiService.get<{ employees: Employee[] }>(`${API_ENDPOINTS.GET_TECHNICIANS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load employees');
      }
    }
  );

  const { data: queriesData, isLoading: queriesLoading } = useQuery(
    'contact-queries',
    () => apiService.get<{ queries: ContactQuery[] }>(`${API_ENDPOINTS.ADMIN_CONTACT_QUERIES}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load contact queries');
      }
    }
  );

  const { data: servicesData, isLoading: servicesLoading } = useQuery(
    'services',
    () => apiService.get<any>(`${API_ENDPOINTS.FETCH_SERVICES}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load services');
      }
    }
  );

  const { data: offersData, isLoading: offersLoading } = useQuery(
    'offers',
    () => apiService.get<any>(`${API_ENDPOINTS.FETCH_OFFERS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load offers');
      }
    }
  );

  // Combine bookings arrays from API response (pending, completed, accepted)
  const bookingsDataAny = bookingsData as any;
  const bookings = [
    ...(bookingsDataAny?.orders?.pending || []),
    ...(bookingsDataAny?.orders?.completed || []),
    ...(bookingsDataAny?.orders?.accepted || [])
  ];

  // Sort bookings by service_date descending (latest first)
  const sortedBookings = bookings.sort((a, b) => new Date(b.service_date).getTime() - new Date(a.service_date).getTime());

  // Employees: use data array from API response and map to UI model
  const employeesDataAny = employeesData as any;
  const employees = (employeesDataAny?.data || []).map((emp: any) => ({
    id: emp.technician_id,
    name: emp.employee_name,
    email: emp.email,
    mobile: emp.phone_number,
    serviceType: emp.service_type,
    address: emp.address,
    idProof: emp.id_proof,
  }));

  // Combine queries arrays if nested (adjust as needed)
  const queriesDataAny = queriesData as any;
  const queries = queriesDataAny?.queries || queriesDataAny?.data?.queries || [];

  // Services: use data array from API response
  const servicesDataAny = servicesData as any;
  const services = servicesDataAny?.services || servicesDataAny?.data?.services || [];

  // Offers: use data array from API response
  const offersDataAny = offersData as any;
  const offers = offersDataAny?.offers || offersDataAny?.data?.offers || [];

  // Add explicit types to map/filter/reduce parameters
  const totalBookings = bookings.length;
  const pendingBookings = bookings.filter((b: Booking) => (b.booking_status && b.booking_status.toLowerCase() === 'pending')).length;
  const completedBookings = bookings.filter((b: Booking) => b.status === 'completed').length;
  const totalRevenue = bookings.reduce((sum: number, b: Booking) => sum + b.total_amount, 0);
  const pendingQueries = queries.filter((q: ContactQuery) => q.status === 'pending').length;

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'accepted':
        return 'bg-blue-100 text-blue-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'cancelled':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const statsCards = [
    {
      title: 'Total Bookings',
      value: totalBookings,
      icon: FiCalendar,
      color: 'bg-blue-500',
      change: '+12%'
    },
    {
      title: 'Pending Bookings',
      value: pendingBookings,
      icon: FiClock,
      color: 'bg-yellow-500',
      change: '+5%'
    },
    {
      title: 'Total Revenue',
      value: `₹${totalRevenue.toLocaleString()}`,
      icon: FiDollarSign,
      color: 'bg-green-500',
      change: '+18%'
    },
    {
      title: 'Active Employees',
      value: employees.length,
      icon: FiUsers,
      color: 'bg-purple-500',
      change: '+2'
    }
  ];

  function handleResetPassword(technicianId: string) {
    if (window.confirm('Are you sure you want to reset the password for this employee? The new password will be set to "12345".')) {
      const sessionId = localStorage.getItem('sessionId');
      axios.post(`${process.env.REACT_APP_API_BASE_URL || ''}reset_password.php`, {
        technician_id: technicianId,
        newpassword: '12345',
      }, {
        headers: {
          'Content-Type': 'application/json',
          'Session-ID': sessionId || '',
        },
      })
        .then((response) => {
          alert(response.data.message || 'Password reset successful!');
        })
        .catch(() => {
          alert('Failed to reset password. Please try again.');
        });
    }
  }

  // Filter queries based on search and filters
  const filteredQueries = queries.filter((query: any) => {
    const search = querySearch.toLowerCase();
    const matchesSearch = (
      (query.customer_name || `${query.first_name} ${query.last_name}`)?.toLowerCase().includes(search) ||
      (query.email || '').toLowerCase().includes(search) ||
      (query.subject || '').toLowerCase().includes(search) ||
      (query.message || '').toLowerCase().includes(search)
    );

    const matchesStatus = statusFilter === 'all' || query.status === statusFilter;

    const matchesDate = (() => {
      if (dateFilter === 'all') return true;
      const queryDate = new Date(query.created_at);
      const now = new Date();
      if (dateFilter === '7days') {
        const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        return queryDate >= sevenDaysAgo;
      }
      if (dateFilter === '30days') {
        const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
        return queryDate >= thirtyDaysAgo;
      }
      return true;
    })();

    return matchesSearch && matchesStatus && matchesDate;
  });

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b">
        <div className="flex items-center justify-between px-6 py-4">
          <div className="flex items-center space-x-3">
            <button
              onClick={() => navigate('/')}
              className="text-gray-600 hover:text-gray-800"
            >
              <FiArrowLeft size={20} />
            </button>
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-teal-500 rounded-lg flex items-center justify-center">
                <FiShield className="text-white" size={16} />
              </div>
              <div>
                <h1 className="text-lg font-bold text-gray-900">NPC Admin</h1>
                <p className="text-xs text-gray-500">Administration Panel</p>
              </div>
            </div>
          </div>
          <div className="flex items-center space-x-4">
            <span className="text-sm text-gray-600">Welcome, {user?.name || 'Admin'}</span>
            <button
              onClick={handleLogout}
              className="text-gray-600 hover:text-gray-800"
              title="Logout"
            >
              <FiLogOut size={18} />
            </button>
          </div>
        </div>
      </div>

      <div className="flex">
        {/* Sidebar Navigation */}
        <div className="w-64 bg-white shadow-sm min-h-screen">
          <div className="p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-6">Admin Dashboard</h2>
            <nav className="space-y-2">
              {[
                { id: 'overview', label: 'Overview', icon: FiBarChart },
                { id: 'bookings', label: 'Bookings', icon: FiCalendar },
                { id: 'employees', label: 'Employees', icon: FiUsers },
                { id: 'queries', label: 'Contact Queries', icon: FiSettings },
                { id: 'services', label: 'Service Details', icon: FiPackage },
                { id: 'offers', label: 'Offer Details', icon: FiGift }
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as any)}
                  className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg text-left transition-colors ${
                    activeTab === tab.id
                      ? 'bg-teal-50 text-teal-700 border-r-2 border-teal-500'
                      : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                  }`}
                >
                  <tab.icon className="w-5 h-5" />
                  <span className="font-medium">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 p-6">
          {/* Overview Tab - Show Stats Cards */}
          {activeTab === 'overview' && (
            <>
              <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Overview</h1>
                <p className="text-gray-600">Manage your business operations</p>
              </div>

              {/* Statistics Cards */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                {statsCards.map((stat, index) => (
                  <motion.div
                    key={stat.title}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.3, delay: index * 0.1 }}
                    className="bg-white rounded-lg shadow-sm p-6"
                  >
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm font-medium text-gray-600">{stat.title}</p>
                        <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                      </div>
                      <div className={`w-12 h-12 ${stat.color} rounded-lg flex items-center justify-center`}>
                        <stat.icon className="w-6 h-6 text-white" />
                      </div>
                    </div>
                  </motion.div>
                ))}
              </div>

              {/* Overview Content */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Recent Bookings */}
                <div className="bg-white rounded-lg shadow-sm p-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Recent Bookings</h3>
                  {bookingsLoading ? (
                    <div className="flex justify-center py-8">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                    </div>
                  ) : bookings.length === 0 ? (
                    <p className="text-gray-500 text-center py-8">No bookings found</p>
                  ) : (
                    <div className="space-y-3">
                      {bookings.slice(0, 5).map((booking: Booking) => (
                        <div key={booking.booking_id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                          <div>
                            <p className="font-medium text-gray-900">{booking.service_name}</p>
                            <p className="text-sm text-gray-600">{formatDate(booking.service_date)}</p>
                          </div>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(String(booking.status || ''))}`}>
                            {booking.status}
                          </span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                {/* Pending Queries */}
                <div className="bg-white rounded-lg shadow-sm p-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Pending Contact Queries</h3>
                  {queriesLoading ? (
                    <div className="flex justify-center py-8">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                    </div>
                  ) : pendingQueries === 0 ? (
                    <p className="text-gray-500 text-center py-8">No pending queries</p>
                  ) : (
                    <div className="space-y-3">
                      {queries.filter((q: ContactQuery) => (q as ContactQuery).status === 'pending').slice(0, 5).map((query: ContactQuery) => (
                        <div key={query.query_id} className="p-3 bg-gray-50 rounded-lg">
                          <p className="font-medium text-gray-900">{query.subject}</p>
                          <p className="text-sm text-gray-600">{query.first_name} {query.last_name}</p>
                          <p className="text-xs text-gray-500">{formatDate(query.created_at)}</p>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </>
          )}

          {/* Bookings Tab */}
          {activeTab === 'bookings' && (
            <div>
              <div className="mb-6">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">All Bookings</h1>
              </div>

              {/* Booking Status Filters */}
              <div className="flex flex-wrap gap-2 mb-6">
                {(['all', 'pending', 'accepted', 'completed'] as const).map((status: 'all' | 'pending' | 'accepted' | 'completed') => (
                  <button
                    key={status}
                    onClick={() => setBookingsTab(status)}
                    className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                      bookingsTab === status
                        ? 'bg-teal-500 text-white'
                        : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'
                    }`}
                  >
                    {status.charAt(0).toUpperCase() + status.slice(1)}
                  </button>
                ))}
              </div>

              {/* Bookings Table */}
              {bookingsLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Service
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Date
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Amount
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Status
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Actions
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {(bookingsTab === 'all' ? sortedBookings :
                          sortedBookings.filter((booking: Booking) => {
                            if (bookingsTab === 'pending') return booking.booking_status === 'pending';
                            if (bookingsTab === 'accepted') return ['accepted', 'confirmed', 'assigned', 'in_progress'].includes((booking.booking_status || '').toLowerCase());
                            if (bookingsTab === 'completed') return booking.booking_status === 'completed';
                            return true;
                          })).map((booking: Booking) => (
                          <tr key={booking.booking_id} className="hover:bg-gray-50">
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-medium text-gray-900">{booking.service_name}</div>
                              <div className="text-sm text-gray-500">{booking.booking_id}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {formatDate(booking.service_date)}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              ₹{booking.total_amount}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(String(booking.booking_status || ''))}`}>
                                {booking.booking_status}
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                              <button
                                onClick={() => {
                                  setSelectedBooking(booking);
                                  setShowBookingModal(true);
                                }}
                                className="text-teal-600 hover:text-teal-900 border border-teal-600 px-3 py-1 rounded hover:bg-teal-50 transition-colors"
                              >
                                <FiEye className="inline w-4 h-4 mr-1" />
                                View
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Employees Tab */}
          {activeTab === 'employees' && (
            <div>
              <div className="mb-6">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Employees</h1>
              </div>

              {employeesLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Employee
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Contact
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Service Type
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Address
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Actions
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {employees.map((employee: Employee) => (
                          <tr key={employee.id} className="hover:bg-gray-50">
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-medium text-gray-900">{employee.name}</div>
                              <div className="text-sm text-gray-500">{employee.email}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {employee.mobile}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {employee.serviceType}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {employee.address}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                              <button
                                onClick={() => handleResetPassword(employee.id)}
                                className="text-red-600 hover:text-red-900"
                              >
                                Reset Password
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Contact Queries Tab */}
          {activeTab === 'queries' && (
            <div>
              <div className="mb-6">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Contact Queries</h1>
              </div>

              <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                <div className="flex flex-col gap-3 p-4">
                  {/* Search and Filter Section */}
                  <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 w-full">
                      <div className="relative w-full sm:w-64">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"><MdSearch size={20} /></span>
                        <input
                          type="text"
                          className="pl-10 pr-3 py-2 w-full border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-teal-400"
                          placeholder="Search queries..."
                          value={querySearch}
                          onChange={e => setQuerySearch(e.target.value)}
                        />
                      </div>
                      <div className="relative">
                        <button
                          title="Filter"
                          className={`p-2 rounded-full border transition ${showFilterDropdown ? 'bg-teal-500 text-white border-teal-500' : 'border-gray-300 bg-white text-gray-700 hover:bg-gray-100'}`}
                          onClick={() => setShowFilterDropdown(!showFilterDropdown)}
                        >
                          <MdFilterList size={22} />
                        </button>
                        {showFilterDropdown && (
                          <div className="absolute top-full left-0 mt-1 w-64 sm:w-72 bg-white border border-gray-300 rounded shadow-lg z-10">
                            <div className="p-3">
                              <h3 className="font-semibold text-gray-700 mb-2">Filter Options</h3>

                              <div className="mb-3">
                                <label className="block text-sm font-medium text-gray-600 mb-1">Status</label>
                                <select
                                  value={statusFilter}
                                  onChange={e => setStatusFilter(e.target.value)}
                                  className="w-full p-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-teal-400"
                                >
                                  <option value="all">All Status</option>
                                  <option value="pending">Pending</option>
                                  <option value="responded">Responded</option>
                                </select>
                              </div>

                              <div className="mb-3">
                                <label className="block text-sm font-medium text-gray-600 mb-1">Date Range</label>
                                <select
                                  value={dateFilter}
                                  onChange={e => setDateFilter(e.target.value)}
                                  className="w-full p-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-teal-400"
                                >
                                  <option value="all">All Time</option>
                                  <option value="7days">Last 7 Days</option>
                                  <option value="30days">Last 30 Days</option>
                                </select>
                              </div>

                              <div className="flex gap-2">
                                <button
                                  onClick={() => {
                                    setStatusFilter('all');
                                    setDateFilter('all');
                                  }}
                                  className="flex-1 px-3 py-1 text-sm border border-gray-300 rounded hover:bg-gray-50"
                                >
                                  Clear
                                </button>
                                <button
                                  onClick={() => setShowFilterDropdown(false)}
                                  className="flex-1 px-3 py-1 text-sm bg-teal-500 text-white rounded hover:bg-teal-600"
                                >
                                  Apply
                                </button>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                    </div>
                    <div className="flex gap-2 justify-start sm:justify-end">
                      <button
                        title="List View"
                        className={`p-2 rounded-full border transition ${queryViewMode === 'table' ? 'bg-teal-500 text-white border-teal-500' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-100'}`}
                        onClick={() => setQueryViewMode('table')}
                      >
                        <MdViewList size={22} />
                      </button>
                      <button
                        title="Card View"
                        className={`p-2 rounded-full border transition ${queryViewMode === 'card' ? 'bg-teal-500 text-white border-teal-500' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-100'}`}
                        onClick={() => setQueryViewMode('card')}
                      >
                        <MdViewModule size={22} />
                      </button>
                    </div>
                  </div>

                  {/* Table/Card Content */}
                  {queriesLoading ? (
                    <div className="flex justify-center py-8">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                    </div>
                  ) : filteredQueries.length === 0 ? (
                    <p className="text-gray-500 text-center py-8">No queries found</p>
                  ) : (
                    <div className="overflow-x-auto">
                      {queryViewMode === 'table' ? (
                        <table className="min-w-full divide-y divide-gray-200 bg-white rounded shadow">
                          <thead className="bg-gray-50">
                            <tr>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Customer</th>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase hidden sm:table-cell">Email</th>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase hidden md:table-cell">Phone</th>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Subject</th>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase hidden sm:table-cell">Date</th>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Status</th>
                              <th className="px-3 sm:px-6 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Actions</th>
                            </tr>
                          </thead>
                          <tbody>
                            {filteredQueries.map((query: any) => (
                              <tr key={query.id} className="hover:bg-gray-50">
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap font-medium text-sm">
                                  <div>{query.customer_name || `${query.first_name} ${query.last_name}`}</div>
                                  <div className="text-xs text-gray-500 sm:hidden">{query.email}</div>
                                </td>
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap text-sm hidden sm:table-cell">{query.email}</td>
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap text-sm hidden md:table-cell">{query.phone}</td>
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap text-sm">{query.subject}</td>
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap text-sm hidden sm:table-cell">{formatDate(query.created_at)}</td>
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap">
                                  <span className={`px-2 py-1 rounded-full text-xs font-semibold ${query.status === 'pending' ? 'bg-yellow-100 text-yellow-800' : 'bg-green-100 text-green-800'}`}>{query.status}</span>
                                </td>
                                <td className="px-3 sm:px-6 py-4 whitespace-nowrap">
                                  <div className="flex flex-col sm:flex-row gap-1">
                                    <button className="flex items-center justify-center gap-1 px-2 py-1 rounded bg-teal-500 text-white hover:bg-teal-600 transition text-xs" onClick={() => { setSelectedQuery(query); setShowQueryModal(true); }}>
                                      <MdVisibility className="text-sm" /> View
                                    </button>
                                    {query.status === 'pending' && (
                                      <button className="flex items-center justify-center gap-1 px-2 py-1 rounded bg-blue-500 text-white hover:bg-blue-600 transition text-xs" onClick={() => { setSelectedQuery(query); setShowRespondModal(true); }}>
                                        <MdReply className="text-sm" /> Reply
                                      </button>
                                    )}
                                  </div>
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      ) : (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                          {filteredQueries.map((query: any) => (
                            <div key={query.id} className="bg-white rounded shadow p-4 border border-gray-100 hover:shadow-lg transition">
                              <div className="font-bold text-lg text-gray-800 mb-1">{query.customer_name || `${query.first_name} ${query.last_name}`}</div>
                              <div className="text-sm text-gray-600 mb-1">{query.email}</div>
                              <div className="text-sm text-gray-700 mb-1 font-medium">{query.subject}</div>
                              <div className="text-xs text-gray-500 mb-2">{formatDate(query.created_at)}</div>
                              <div className="mb-2 text-gray-700 text-sm">{query.message?.slice(0, 80)}{query.message?.length > 80 ? '...' : ''}</div>
                              <div className="flex flex-col sm:flex-row gap-2 mt-2">
                                <button className="flex items-center justify-center gap-1 px-3 py-1 rounded bg-teal-500 text-white hover:bg-teal-600 transition text-sm" onClick={() => { setSelectedQuery(query); setShowQueryModal(true); }}>
                                  <MdVisibility className="text-base" /> View Details
                                </button>
                                {query.status === 'pending' && (
                                  <button className="flex items-center justify-center gap-1 px-3 py-1 rounded bg-blue-500 text-white hover:bg-blue-600 transition text-sm" onClick={() => { setSelectedQuery(query); setShowRespondModal(true); }}>
                                    <MdReply className="text-base" /> Reply
                                  </button>
                                )}
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}

          {/* Service Details Tab */}
          {activeTab === 'services' && (
            <div>
              <div className="mb-6">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Service Details</h1>
                <p className="text-gray-600">Manage and view all services</p>
              </div>

              {servicesLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Service Name
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Service Types
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Pricing
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Status
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Actions
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {services.map((service: any) => (
                          <tr key={service.service_id} className="hover:bg-gray-50">
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-medium text-gray-900">{service.service_name}</div>
                              <div className="text-sm text-gray-500">{service.description}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {service.service_types?.length || 0} types
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              Starting from ₹{service.min_price || 'N/A'}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className="px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                                Active
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                              <button className="text-teal-600 hover:text-teal-900 border border-teal-600 px-3 py-1 rounded hover:bg-teal-50 transition-colors">
                                <FiEye className="inline w-4 h-4 mr-1" />
                                View Details
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Offer Details Tab */}
          {activeTab === 'offers' && (
            <div>
              <div className="mb-6">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Offer Details</h1>
                <p className="text-gray-600">Manage and view all offers</p>
              </div>

              {offersLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                  <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Offer Name
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Coupon Code
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Discount
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Validity
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Status
                          </th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                            Actions
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y divide-gray-200">
                        {offers.map((offer: any) => (
                          <tr key={offer.offer_id} className="hover:bg-gray-50">
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-medium text-gray-900">{offer.offer_name}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {offer.coupon_number}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {offer.offer_percentage}% off
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                              {formatDate(offer.offer_starts_on)} - {formatDate(offer.expires_on)}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                                offer.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                              }`}>
                                {offer.status}
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                              <button className="text-teal-600 hover:text-teal-900 border border-teal-600 px-3 py-1 rounded hover:bg-teal-50 transition-colors">
                                <FiEye className="inline w-4 h-4 mr-1" />
                                View Details
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Booking Details Modal */}
      {showBookingModal && selectedBooking && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-40">
          <div className="bg-white rounded-lg shadow-lg max-w-lg w-full p-6 relative">
            <button className="absolute top-2 right-2 text-gray-400 hover:text-gray-600" onClick={() => setShowBookingModal(false)}>&times;</button>
            <h2 className="text-xl font-bold mb-4">Booking Details</h2>
            <div className="space-y-2">
              <div><b>Service:</b> {selectedBooking.service_name}</div>
              <div><b>Date:</b> {formatDate(selectedBooking.service_date)}</div>
              <div><b>Time Slot:</b> {selectedBooking.time_slot}</div>
              <div><b>Customer Name:</b> {selectedBooking.customer_name}</div>
              <div><b>Email:</b> {selectedBooking.customer_email}</div>
              <div><b>Phone:</b> {selectedBooking.customer_phone}</div>
              <div><b>Address:</b> {selectedBooking.service_address}</div>
              <div><b>Special Notes:</b> {selectedBooking.special_notes}</div>
              <div><b>Payment Method:</b> {selectedBooking.payment_method}</div>
              <div><b>Payment Status:</b> {selectedBooking.payment_status}</div>
              <div><b>Status:</b> {selectedBooking.booking_status}</div>
              <div><b>Assigned Technician:</b> {selectedBooking.assigned_technician_name || 'Not assigned'}</div>
              <div><b>Technician Phone:</b> {selectedBooking.technician_phone || '-'}</div>
            </div>
            <div className="flex space-x-2 mt-6">
              {/* Assign Button for Pending, Accepted, or Confirmed */}
              {(['pending', 'confirmed', 'accepted'].includes(selectedBooking.booking_status || '') && !selectedBooking.assigned_technician_name) && (
                <>
                  <select
                    className="border rounded px-2 py-1"
                    value={assignTechId}
                    onChange={e => setAssignTechId(e.target.value)}
                  >
                    <option value="">Select Technician</option>
                    {employees.map((tech: Employee) => (
                      <option key={tech.id} value={tech.id}>{tech.name} ({tech.mobile})</option>
                    ))}
                  </select>
                  <button
                    className="btn btn-primary"
                    disabled={assignLoading || !assignTechId}
                    onClick={async () => {
                      setAssignLoading(true);
                      try {
                        const sessionId = localStorage.getItem('sessionId');
                        await axios.post(getApiUrl('assign_technicians.php'), {
                          booking_id: selectedBooking.booking_id,
                          technician_id: assignTechId,
                        }, {
                          headers: {
                            'Content-Type': 'application/json',
                            'Session-ID': sessionId || '',
                          },
                        });
                        toast.success('Technician assigned!');
                        setShowBookingModal(false);
                        window.location.reload();
                      } catch {
                        toast.error('Failed to assign technician.');
                      } finally {
                        setAssignLoading(false);
                      }
                    }}
                  >
                    {assignLoading ? 'Assigning...' : 'Assign'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {showQueryModal && selectedQuery && (
        <Modal onClose={() => setShowQueryModal(false)}>
          <h2 className="text-xl font-bold mb-4 text-teal-700">Query Details</h2>
          <div className="space-y-2">
            <div><b>Customer:</b> {selectedQuery.customer_name || `${selectedQuery.first_name} ${selectedQuery.last_name}`}</div>
            <div><b>Email:</b> {selectedQuery.email}</div>
            <div><b>Phone:</b> {selectedQuery.phone}</div>
            <div><b>Subject:</b> {selectedQuery.subject}</div>
            <div><b>Date:</b> {formatDate(selectedQuery.created_at)}</div>
            <div><b>Message:</b> <div className="bg-gray-50 rounded p-2 mt-1 text-gray-700 whitespace-pre-line">{selectedQuery.message}</div></div>
            {selectedQuery.admin_response && (
              <div className="mt-2"><b>Admin Response:</b> <div className="bg-green-50 rounded p-2 mt-1 text-green-700 whitespace-pre-line">{selectedQuery.admin_response}</div></div>
            )}
            {selectedQuery.response_date_formatted && (
              <div className="text-xs text-gray-500">Responded: {selectedQuery.response_date_formatted}</div>
            )}
          </div>
          <div className="flex justify-end gap-2 mt-6">
            {selectedQuery.status === 'pending' && (
              <button 
                className="px-4 py-2 rounded bg-blue-500 text-white hover:bg-blue-600 transition"
                onClick={() => {
                  setShowQueryModal(false);
                  setShowRespondModal(true);
                }}
              >
                Reply
              </button>
            )}
            <button className="px-4 py-2 rounded bg-gray-200 text-gray-700 hover:bg-gray-300 transition" onClick={() => setShowQueryModal(false)}>Close</button>
          </div>
        </Modal>
      )}
      {showRespondModal && selectedQuery && (
        <Modal onClose={() => setShowRespondModal(false)}>
          <h2 className="text-xl font-bold mb-4 text-blue-700">Respond to Query</h2>
          <textarea value={respondText} onChange={e => setRespondText(e.target.value)} rows={5} className="w-full border border-gray-300 rounded p-2 focus:outline-none focus:ring-2 focus:ring-blue-400" placeholder="Type your response..." />
          <div className="flex justify-end gap-2 mt-4">
            <button className="px-4 py-2 rounded bg-gray-200 text-gray-700 hover:bg-gray-300 transition" onClick={() => setShowRespondModal(false)}>Cancel</button>
            <button className="px-4 py-2 rounded bg-blue-500 text-white hover:bg-blue-600 transition disabled:opacity-50" disabled={respondLoading || respondText.length < 10} onClick={async () => {
              setRespondLoading(true);
              try {
                await apiService.post('admin_contact_queries.php', {
                  query_id: selectedQuery.id,
                  response: respondText,
                  status: 'responded',
                });
                toast.success('Response submitted!');
                setShowRespondModal(false);
                setRespondText('');
                // Optionally refresh queries here
              } catch {
                toast.error('Failed to submit response.');
              } finally {
                setRespondLoading(false);
              }
            }}>Send Response</button>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default AdminDashboard;
